module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);

reg [1:0] count;
reg [9:0] sum;
reg [1:0] state;
parameter IDLE = 2'b00;
parameter INPUT = 2'b01;
parameter ACCUMULATE = 2'b10;
parameter OUTPUT = 2'b11;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        count <= 2'b00;
        sum <= 10'b0;
        valid_out <= 1'b0;
        data_out <= 10'b0;
    end else begin
        case (state)
            IDLE: begin
                if (valid_in) begin
                    state <= INPUT;
                    count <= 2'b01;
                    sum <= {2'b00, data_in};
                end else begin
                    state <= IDLE;
                    count <= 2'b00;
                    sum <= 10'b0;
                end
            end
            INPUT: begin
                if (count == 2'b11) begin
                    state <= ACCUMULATE;
                    count <= 2'b00;
                    sum <= sum + {2'b00, data_in};
                end else begin
                    state <= INPUT;
                    count <= count + 1;
                    sum <= sum + {2'b00, data_in};
                end
            end
            ACCUMULATE: begin
                state <= OUTPUT;
            end
            OUTPUT: begin
                state <= IDLE;
                valid_out <= 1'b0;
                data_out <= sum;
            end
            default: begin
                state <= IDLE;
                count <= 2'b00;
                sum <= 10'b0;
            end
        endcase
    end
end

endmodule
